1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	
14	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
15	type Damage = { itemType: string; amount: number };
16	type Incident = { cause: string; damages: Damage[] };
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
19	type Step = QuoteStep | ClaimStep;
20	type Customer = { yearsWithMHPCO: number };
21	type Scenario = { customer: Customer; steps: Step[] };
22	
23	type ItemTypeSpec = { basePremium: number; insuranceValue: number; isComponent: boolean };
24	
25	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
26	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
27	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
28	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
29	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
30	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
31	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
32	};
33	
34	const basePremiumFor = (item: Item): number => ITEM_TYPES[item.type].basePremium;
35	
36	const countByType = (items: Item[]): Map<string, number> => {
37	  const counts = new Map<string, number>();
38	  for (const item of items) {
39	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
40	  }
41	  return counts;
42	};
43	
44	const premiumForTypeCount = (type: string, count: number): number => {
45	  const spec = ITEM_TYPES[type];
46	  return spec.isComponent && count === BLOCK_SIZE
47	    ? BLOCK_PREMIUM
48	    : count * spec.basePremium;
49	};
50	
51	const basePremiumOf = (items: Item[]): number => {
52	  let total = 0;
53	  for (const [type, count] of countByType(items)) {
54	    total += premiumForTypeCount(type, count);
55	  }
56	  return total;
57	};
58	
59	type SurchargeRule = { applies: (item: Item) => boolean; rate: number };
60	
61	const SURCHARGE_RULES: SurchargeRule[] = [
62	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
63	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
64	];
65	
66	const surchargeRateFor = (item: Item): number =>
67	  SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
68	
69	const itemSurchargesOf = (items: Item[]): number =>
70	  items.reduce((sum, item) => sum + basePremiumFor(item) * surchargeRateFor(item), 0);
71	
72	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
73	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
74	    ? basePremium * LOYALTY_DISCOUNT_RATE
75	    : 0;
76	
77	const followUpDiscountFor = (basePremium: number, stepIndex: number): number =>
78	  stepIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
79	
80	const quoteForStep = ({ items }: QuoteStep, customer: Customer, stepIndex: number) => {
81	  const basePremium = basePremiumOf(items);
82	  const itemSurcharges = itemSurchargesOf(items);
83	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
84	  const loyaltyDiscount = loyaltyDiscountFor(basePremium, customer);
85	  const followUpDiscount = followUpDiscountFor(basePremium, stepIndex);
86	  return {
87	    premium: Math.ceil(
88	      basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
89	    ),
90	  };
91	};
92	
93	type Policy = { items: Item[]; cap: number };
94	
95	const policyFor = (items: Item[]): Policy => {
96	  const insuranceSum = items.reduce((sum, item) => sum + ITEM_TYPES[item.type].insuranceValue, 0);
97	  return { items, cap: insuranceSum * CAP_MULTIPLIER };
98	};
99	
100	const claimForStep = ({ incident }: ClaimStep, policies: Map<number, Policy>, policyIndex: number) => {
101	  const policy = policies.get(policyIndex)!;
102	  const payout = incident.damages.reduce((sum, dmg) => sum + (dmg.amount - DEDUCTIBLE), 0);
103	  return { payout, remainingCap: policy.cap - payout };
104	};
105	
106	export const runScenario = (scenario: Scenario): unknown => {
107	  const policies = new Map<number, Policy>();
108	  const results = scenario.steps.map((step, i) => {
109	    if (step.op === "quote") {
110	      policies.set(i, policyFor(step.items));
111	      return quoteForStep(step, scenario.customer, i);
112	    }
113	    return claimForStep(step, policies, step.policy);
114	  });
115	  return { results };
116	};
